        /* Peek */
        iov.iov_base = &data;
        iov.iov_len = 1;
        memset(&msg, 0, sizeof(msg));
        msg.msg_iov = &iov;
        msg.msg_iovlen = 1;
        msg.msg_control = ctrl_buf;
        msg.msg_controllen = sizeof(ctrl_buf);

        ret = recvmsg(sv[1], &msg, MSG_PEEK);
        if (ret < 0)
            continue;

        /* Now consume */
        iov.iov_base = &data;
        iov.iov_len = 1;
